4	type Scenario = { steps: { op: string; items: unknown[] }[] };
5	
6	export function runScenario(scenario: unknown): unknown {
7	  const items = (scenario as Scenario).steps[0].items;
8	  return { results: [{ premium: items.length * RUNE_BASE_PREMIUM + PROCESSING_FEE }] };
9	}
